import type { Metadata } from "next";
import { IBM_Plex_Sans_Arabic } from "next/font/google";

import { Footer } from "@/components/layout/Footer";
import { Header } from "@/components/layout/Header";
import { Providers } from "@/components/providers/Providers";
import { getServerLanguage } from "@/lib/server-language";
import { getDirection } from "@/lib/storefront";
import { createServerSupabaseClient } from "@/lib/supabase";

import "./globals.css";

const ibmPlex = IBM_Plex_Sans_Arabic({
  weight: ["400", "500", "600", "700"],
  subsets: ["arabic", "latin"],
  variable: "--font-ibm",
  display: "swap",
});

export const metadata: Metadata = {
  title: "الأمل سنتر | Al-Amal Center",
  description: "Customer-facing storefront for Al-Amal Center.",
};

export const dynamic = "force-dynamic";

export default async function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  const language = await getServerLanguage();
  const supabase = await createServerSupabaseClient();
  const {
    data: { session },
  } = await supabase.auth.getSession();

  return (
    <html
      lang={language}
      dir={getDirection(language)}
      suppressHydrationWarning
    >
      <body
        className={`${ibmPlex.variable} bg-background font-ibm text-slate-900 antialiased`}
      >
        <Providers initialLanguage={language} initialSession={session}>
          <div className="min-h-screen bg-brand-grid bg-[size:28px_28px]">
            <div className="min-h-screen bg-[radial-gradient(circle_at_top,rgba(46,125,50,0.10),transparent_30%),linear-gradient(180deg,#f9fcf9_0%,#f5f5f5_100%)]">
              <Header />
              <main className="mx-auto w-full max-w-7xl px-4 py-6 sm:px-6 lg:px-8">
                {children}
              </main>
              <Footer />
            </div>
          </div>
        </Providers>
      </body>
    </html>
  );
}
